# Select the strategy variant.
STRATEGY_VERSION = "producerlite_0615_K_2p_producer_style"
SUBMISSION_VARIANT = "candidate_0615_K_L0014_2p_producer_style"

from pathlib import Path
import base64
import hashlib
import tarfile

ARCHIVES = {
    'candidate_0615_K_L0014_2p_producer_style': {
        'sha256': '2fec83a61bacf8ba4958aded02ab552c83f6731f00492813fa038f5887c9765f',
        'size': 54984,
        'b64': '',
    },
}

if SUBMISSION_VARIANT not in ARCHIVES:
    raise ValueError(f"Unknown SUBMISSION_VARIANT: {SUBMISSION_VARIANT!r}. Available: {sorted(ARCHIVES)}")

selected = ARCHIVES[SUBMISSION_VARIANT]
raw = base64.b64decode(selected['b64'])
digest = hashlib.sha256(raw).hexdigest()
if digest != selected['sha256']:
    raise RuntimeError(f"Archive checksum mismatch: {digest} != {selected['sha256']}")
if len(raw) != selected['size']:
    raise RuntimeError(f"Archive size mismatch: {len(raw)} != {selected['size']}")

out_path = Path('submission.tar.gz')
out_path.write_bytes(raw)
with tarfile.open(out_path, 'r:gz') as tar:
    names = set(tar.getnames())
required = {'main.py', 'params.json'}
missing = sorted(required - names)
if missing:
    raise RuntimeError(f"Archive missing required files: {missing}")
print(f"Wrote {out_path} ({len(raw):,} bytes) for {SUBMISSION_VARIANT}")
print(f"sha256: {digest}")